import React from 'react';
import { Route, Switch } from 'react-router-dom';
import { QueryClient, QueryClientProvider } from 'react-query';
import AppProviders from './providers/AppProviders';
import Navbar from './components/layout/Navbar';
import Footer from './components/layout/Footer';
import ProtectedRoute from './components/auth/ProtectedRoute';
import SubscriptionRoute from './components/subscription/SubscriptionRoute';

// Pages
import MarketingHome from './pages/MarketingHome';
import Login from './pages/auth/Login';
import Register from './pages/auth/Register';
import Dashboard from './pages/Dashboard';
import WorkoutDetail from './pages/WorkoutDetail';
import Help from './pages/Help'; // New Help page
import BasicContent from './pages/subscription/BasicContent';
import PremiumContent from './pages/subscription/PremiumContent';
import EliteContent from './pages/subscription/EliteContent';

// Create React Query client
const queryClient = new QueryClient({
  defaultOptions: {
    queries: {
      refetchOnWindowFocus: false,
      retry: 1,
    },
  },
});

function App() {
  return (
    <QueryClientProvider client={queryClient}>
      <AppProviders>
        <div className="flex flex-col min-h-screen">
          <Navbar />
          <main className="flex-grow">
            <Switch>
              <Route exact path="/" component={MarketingHome} />
              <Route path="/login" component={Login} />
              <Route path="/register" component={Register} />
              <ProtectedRoute path="/dashboard" component={Dashboard} />
              <ProtectedRoute path="/workout/:id" component={WorkoutDetail} />
              <ProtectedRoute path="/help" component={Help} /> {/* New Help route */}
              <ProtectedRoute path="/basic" component={BasicContent} />
              <SubscriptionRoute 
                path="/premium" 
                component={PremiumContent} 
                requiredTier="premium" 
              />
              <SubscriptionRoute 
                path="/elite" 
                component={EliteContent} 
                requiredTier="elite" 
              />
              <Route path="*">
                <div className="container mx-auto px-4 py-16 text-center">
                  <h1 className="text-4xl font-bold mb-4">Page Not Found</h1>
                  <p className="mb-8">Sorry, the page you're looking for doesn't exist.</p>
                  <a 
                    href="/" 
                    className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-lg"
                  >
                    Return Home
                  </a>
                </div>
              </Route>
            </Switch>
          </main>
          <Footer />
        </div>
      </AppProviders>
    </QueryClientProvider>
  );
}

export default App;
